#include <bits/stdc++.h>
using namespace std;
struct m{
	int i,n;
}a[1000];
int main(void){
	int l,f=0;
	std::cin>>l;
	for(int i=1;i<=l;i++)std::cin>>a[i].n,a[i].i=i;
	for(int i=1;i<=l;i++){
		for(int j=i+1;j<=l;j++){
			if(a[j].n<a[i].n){
				swap(a[j],a[i]);
			}
		}
	}
	for(int i=1;i<=l;i++)std::cout<<a[i].i+1<<" ";
	std::cout<<endl;
	for(int i=1;i<=l;i++){
		f+=(l-i)*a[i].n;
	}
	std::printf("%0.2lf",(double(f)/double(l)));
    return 0;
}
